106→    private void autoSelectNewestFiles() {
107→        // 自动选择Download/Weixin目录中最新的一对文件（音频+文档）
108→        new Thread(() -> {
109→            try {
110→                File downloadDir = new File(Environment.getExternalStorageDirectory(), "Download");
111→                File weixinDir = new File(downloadDir, "Weixin");
112→                File targetDir = weixinDir.exists() ? weixinDir : downloadDir;
113→
114→                File[] files = targetDir.listFiles();
115→                if (files == null || files.length == 0) return;
116→
117→                // 按修改时间排序，最新的在前
118→                java.util.Arrays.sort(files, (a, b) -> Long.compare(b.lastModified(), a.lastModified()));
119→
120→                File newestAudio = null;
121→                File newestDoc = null;
122→
123→                // 找最新的音频和文档
124→                for (File f : files) {
125→                    String name = f.getName().toLowerCase();
126→                    if (newestAudio == null && isAudioFile(name)) {
127→                        newestAudio = f;
128→                    } else if (newestDoc == null && isDocFile(name)) {
129→                        newestDoc = f;
130→                    }
131→                    if (newestAudio != null && newestDoc != null) break;
132→                }
133→
134→                // 自动填充
135→                if (newestAudio != null) {
136→                    String path = newestAudio.getAbsolutePath();
137→                    audioPath = path;
138→                    final String name = newestAudio.getName();
139→                    runOnUiThread(() -> tvAudioName.setText(name));
140→                    Log.i(TAG, "自动选择音频: " + name);
141→                }
142→                if (newestDoc != null) {
143→                    String path = newestDoc.getAbsolutePath();
144→                    docPath = path;
145→                    final String name = newestDoc.getName();
146→                    runOnUiThread(() -> tvDocName.setText(name));
147→                    Log.i(TAG, "自动选择文档: " + name);
148→                }
149→            } catch (Exception e) {
150→                Log.e(TAG, "自动选择文件失败", e);
151→            }
152→        }).start();
153→    }
