187→    private void handleShareIntent(Intent intent) {
188→        if (intent == null) return;
189→        String action = intent.getAction();
190→        if (Intent.ACTION_SEND.equals(action)) {
191→            Uri uri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
192→            if (uri != null) importFile(uri);
193→        } else if (Intent.ACTION_SEND_MULTIPLE.equals(action)) {
194→            java.util.ArrayList<Uri> uris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
