252→    private void pickFile(String mimeType, int requestCode) {
253→        Intent i = new Intent(Intent.ACTION_GET_CONTENT);
254→        i.setType(mimeType);
255→        i.addCategory(Intent.CATEGORY_OPENABLE);
256→
257→        // 尝试设置默认路径为Download/Weixin
258→        try {
259→            // Android 7.0+ 使用Storage Access Framework
260→            if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
261→                // 尝试指向Download目录
262→                android.net.Uri downloadsUri = android.net.Uri.parse("content://com.android.externalstorage.documents/document/primary:Download");
263→                // 尝试指向Weixin子目录
264→                android.net.Uri weixinUri = android.net.Uri.parse("content://com.android.externalstorage.documents/document/primary:Download/Weixin");
265→
266→                // 先尝试Weixin目录
267→                i.putExtra(DocumentsContract.EXTRA_INITIAL_URI, weixinUri.toString());
268→            }
269→        } catch (Exception e) {
270→            Log.w(TAG, "无法设置默认文件路径", e);
271→        }
272→
273→        startActivityForResult(i, requestCode);
