276→    @Override
277→    protected void onActivityResult(int requestCode, int resultCode, Intent data) {
278→        super.onActivityResult(requestCode, resultCode, data);
279→        if (resultCode != RESULT_OK || data == null) return;
280→        Uri uri = data.getData();
281→        if (uri == null) return;
282→        String path = copyToCache(uri);
283→        if (path == null) return;
284→        String name = getFileName(uri);
285→        if (requestCode == 1) {
286→            audioPath = path;
287→            tvAudioName.setText(name);
288→        } else {
289→            docPath = path;
290→            tvDocName.setText(name);
291→        }
292→    }
