294→    private void importFile(Uri uri) {
295→        String path = copyToCache(uri);
296→        if (path == null) return;
297→        String name = getFileName(uri).toLowerCase();
298→        if (name.endsWith(".wav") || name.endsWith(".mp3") || name.endsWith(".m4a") ||
299→            name.endsWith(".flac") || name.endsWith(".amr") || name.endsWith(".silk") ||
300→            name.endsWith(".ogg") || name.endsWith(".opus") || name.endsWith(".aac")) {
301→            audioPath = path;
302→            tvAudioName.setText(getFileName(uri));
303→        } else {
304→            docPath = path;
305→            tvDocName.setText(getFileName(uri));
306→        }
307→        tvStatus.setText("已从微信导入文件");
308→    }
309→
310→    private String copyToCache(Uri uri) {
311→        try {
312→            InputStream is = getContentResolver().openInputStream(uri);
313→            String name = getFileName(uri);
314→            File out = new File(getCacheDir(), name);
315→            FileOutputStream fos = new FileOutputStream(out);
316→            byte[] buf = new byte[8192];
317→            int n;
318→            while ((n = is.read(buf)) != -1) fos.write(buf, 0, n);
319→            fos.close();
320→            is.close();
321→            return out.getAbsolutePath();
322→        } catch (Exception e) {
323→            tvStatus.setText("文件导入失败: " + e.getMessage());
324→            return null;
325→        }
326→    }
327→
328→    private String getFileName(Uri uri) {
329→        String name = "file";
330→        Cursor c = getContentResolver().query(uri, null, null, null, null);
331→        if (c != null && c.moveToFirst()) {
332→            int idx = c.getColumnIndex(OpenableColumns.DISPLAY_NAME);
333→            if (idx >= 0) name = c.getString(idx);
334→            c.close();
335→        }
336→        return name;
337→    }
338→
339→    // ===== 音频解码：支持所有格式(WAV/MP3/M4A/FLAC/AMR/OGG...) =====
340→    private float[] decodeAudio(String filepath) throws Exception {
341→        MediaExtractor extractor = new MediaExtractor();
342→        extractor.setDataSource(filepath);
343→
344→        // 查找音频轨道
345→        int trackIndex = -1;
346→        MediaFormat format = null;
347→        for (int i = 0; i < extractor.getTrackCount(); i++) {
348→            MediaFormat f = extractor.getTrackFormat(i);
349→            String mime = f.getString(MediaFormat.KEY_MIME);
350→            if (mime != null && mime.startsWith("audio/")) {
351→                trackIndex = i;
352→                format = f;
353→                break;
354→            }
355→        }
356→        if (trackIndex < 0) {
357→            throw new Exception("未找到音频轨道，文件可能不是音频格式");
358→        }
359→
360→        extractor.selectTrack(trackIndex);
361→        String mime = format.getString(MediaFormat.KEY_MIME);
362→        int sampleRate = format.getInteger(MediaFormat.KEY_SAMPLE_RATE);
363→        int channels = format.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
364→        Log.i(TAG, "音频格式: " + mime + ", " + sampleRate + "Hz, " + channels + "ch");
365→
366→        ByteArrayOutputStream pcmOut = new ByteArrayOutputStream();
367→
368→        if ("audio/raw".equals(mime)) {
369→            // PCM WAV: 直接从extractor读取，不需要codec解码
370→            ByteBuffer buf = ByteBuffer.allocate(65536);
371→            while (extractor.readSampleData(buf, 0) >= 0) {
372→                int pos = buf.position();
373→                byte[] chunk = new byte[pos];
374→                buf.flip();
375→                buf.get(chunk);
376→                pcmOut.write(chunk);
377→                buf.clear();
378→                extractor.advance();
379→            }
380→        } else {
381→            // 压缩格式(MP3/AAC/FLAC/AMR等): 用MediaCodec解码
382→            MediaCodec codec = MediaCodec.createDecoderByType(mime);
383→            codec.configure(format, null, null, 0);
384→            codec.start();
385→
386→            MediaCodec.BufferInfo info = new MediaCodec.BufferInfo();
387→            boolean inputDone = false;
388→            boolean outputDone = false;
389→
390→            while (!outputDone) {
391→                // 送入压缩数据
392→                if (!inputDone) {
393→                    int inputIdx = codec.dequeueInputBuffer(10000);
394→                    if (inputIdx >= 0) {
395→                        ByteBuffer inputBuf = codec.getInputBuffer(inputIdx);
396→                        int size = extractor.readSampleData(inputBuf, 0);
397→                        if (size < 0) {
398→                            codec.queueInputBuffer(inputIdx, 0, 0, 0,
399→                                MediaCodec.BUFFER_FLAG_END_OF_STREAM);
400→                            inputDone = true;
401→                        } else {
402→                            codec.queueInputBuffer(inputIdx, 0, size,
403→                                extractor.getSampleTime(), 0);
404→                            extractor.advance();
405→                        }
406→                    }
407→                }
408→
409→                // 取出PCM数据
410→                int outputIdx = codec.dequeueOutputBuffer(info, 10000);
411→                if (outputIdx >= 0) {
412→                    if ((info.flags & MediaCodec.BUFFER_FLAG_END_OF_STREAM) != 0) {
413→                        outputDone = true;
414→                    }
415→                    if (info.size > 0) {
416→                        ByteBuffer outputBuf = codec.getOutputBuffer(outputIdx);
417→                        byte[] chunk = new byte[info.size];
418→                        outputBuf.get(chunk);
419→                        pcmOut.write(chunk);
420→                    }
421→                    codec.releaseOutputBuffer(outputIdx, false);
422→                } else if (outputIdx == MediaCodec.INFO_OUTPUT_FORMAT_CHANGED) {
423→                    MediaFormat outFmt = codec.getOutputFormat();
424→                    sampleRate = outFmt.getInteger(MediaFormat.KEY_SAMPLE_RATE);
425→                    channels = outFmt.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
426→                    Log.i(TAG, "解码输出格式: " + sampleRate + "Hz, " + channels + "ch");
427→                }
428→            }
429→
430→            codec.stop();
431→            codec.release();
432→        }
433→
434→        extractor.release();
435→
436→        byte[] pcmBytes = pcmOut.toByteArray();
437→        if (pcmBytes.length < 100) {
438→            throw new Exception("音频解码后数据为空 (原格式: " + mime + ")");
439→        }
440→
441→        // PCM bytes -> float samples (16-bit little-endian)
442→        int numSamples = pcmBytes.length / 2;
443→        float[] allSamples = new float[numSamples];
444→        ByteBuffer bb = ByteBuffer.wrap(pcmBytes).order(ByteOrder.LITTLE_ENDIAN);
445→        for (int i = 0; i < numSamples; i++) {
446→            allSamples[i] = bb.getShort() / 32768.0f;
447→        }
448→
449→        // 立体声 -> 单声道
450→        float[] mono;
451→        if (channels > 1) {
452→            int monoLen = numSamples / channels;
453→            mono = new float[monoLen];
454→            for (int i = 0; i < monoLen; i++) {
455→                float sum = 0;
456→                for (int c = 0; c < channels; c++) {
457→                    sum += allSamples[i * channels + c];
458→                }
459→                mono[i] = sum / channels;
460→            }
461→        } else {
462→            mono = allSamples;
463→        }
464→
465→        // 重采样到16kHz
466→        if (sampleRate != 16000) {
467→            Log.i(TAG, "重采样: " + sampleRate + "Hz -> 16000Hz");
468→            mono = resample(mono, sampleRate, 16000);
469→        }
470→
471→        float durationSec = mono.length / 16000.0f;
472→        Log.i(TAG, "解码完成: " + mono.length + " samples, " +
473→            String.format("%.1f", durationSec) + "s @ 16kHz mono");
474→
475→        if (durationSec < 0.3f) {
476→            throw new Exception("音频太短 (" + String.format("%.1f", durationSec) + "秒)，无法识别");
477→        }
478→
479→        return mono;
480→    }
