482→    // ===== 线性插值重采样 =====
483→    private float[] resample(float[] input, int fromRate, int toRate) {
484→        double ratio = (double) fromRate / toRate;
485→        int outputLen = (int) (input.length / ratio);
486→        float[] output = new float[outputLen];
487→        for (int i = 0; i < outputLen; i++) {
488→            double srcIdx = i * ratio;
489→            int idx = (int) srcIdx;
490→            double frac = srcIdx - idx;
491→            if (idx + 1 < input.length) {
492→                output[i] = (float) (input[idx] * (1 - frac) + input[idx + 1] * frac);
493→            } else if (idx < input.length) {
494→                output[i] = input[idx];
495→            }
496→        }
497→        return output;
498→    }
