500→    // ===== 将任意音频转为16kHz单声道WAV（供Python端ASR使用） =====
501→    private String convertToWav(String audioFile) throws Exception {
502→        float[] samples = decodeAudio(audioFile);
503→        lastAudioDuration = samples.length / 16000.0f;
504→        File wavFile = new File(getCacheDir(), "asr_input.wav");
505→        int dataLen = samples.length * 2;
506→        int fileLen = 44 + dataLen;
507→        FileOutputStream fos = new FileOutputStream(wavFile);
508→        ByteBuffer header = ByteBuffer.allocate(44).order(ByteOrder.LITTLE_ENDIAN);
509→        header.put("RIFF".getBytes()); header.putInt(fileLen - 8);
510→        header.put("WAVE".getBytes()); header.put("fmt ".getBytes());
511→        header.putInt(16); header.putShort((short) 1); header.putShort((short) 1);
512→        header.putInt(16000); header.putInt(32000); header.putShort((short) 2); header.putShort((short) 16);
513→        header.put("data".getBytes()); header.putInt(dataLen);
514→        fos.write(header.array());
515→        ByteBuffer buf = ByteBuffer.allocate(samples.length * 2).order(ByteOrder.LITTLE_ENDIAN);
516→        for (float s : samples) buf.putShort((short) Math.max(-32768, Math.min(32767, (int)(s * 32767))));
517→        fos.write(buf.array());
518→        fos.close();
519→        Log.i(TAG, "转换WAV: " + String.format("%.1f", lastAudioDuration) + "s");
520→        return wavFile.getAbsolutePath();
521→    }
