523→    // ===== Sherpa-ONNX 离线识别（分段提升准确率） =====
524→    private String transcribeSherpa(String audioFile) throws Exception {
525→        // 解码音频为16kHz单声道（支持WAV/MP3/M4A/FLAC/AMR/OGG等）
526→        float[] samples = decodeAudio(audioFile);
527→        lastAudioDuration = samples.length / 16000.0f;  // 记录音频时长
528→
529→        AssetManager assetManager = getAssets();
530→
531→        OfflineParaformerModelConfig paraformerConfig = new OfflineParaformerModelConfig();
532→        paraformerConfig.setModel("models/paraformer/model.int8.onnx");
533→
534→        OfflineModelConfig modelConfig = new OfflineModelConfig();
535→        modelConfig.setParaformer(paraformerConfig);
536→        modelConfig.setTokens("models/paraformer/tokens.txt");
537→        modelConfig.setNumThreads(4);
538→        modelConfig.setDebug(false);
539→
540→        OfflineRecognizerConfig config = new OfflineRecognizerConfig();
541→        config.setModelConfig(modelConfig);
542→        config.setDecodingMethod("greedy_search");
543→
544→        OfflineRecognizer recognizer = new OfflineRecognizer(assetManager, config);
545→
546→        // 分段识别：每段30秒，提高长音频准确率
547→        int chunkSamples = 30 * 16000;
548→        int totalChunks = (int) Math.ceil((double) samples.length / chunkSamples);
549→        StringBuilder allText = new StringBuilder();
550→
551→        if (totalChunks <= 1) {
552→            // 短音频直接识别
553→            OfflineStream stream = recognizer.createStream();
554→            stream.acceptWaveform(samples, 16000);
555→            recognizer.decode(stream);
556→            OfflineRecognizerResult result = recognizer.getResult(stream);
557→            allText.append(result.getText() != null ? result.getText().trim() : "");
558→            stream.release();
559→        } else {
560→            // 长音频分段识别
561→            for (int ci = 0; ci < totalChunks; ci++) {
562→                int finalCi = ci;
563→                runOnUiThread(() -> tvStatus.setText(
564→                    String.format("离线识别 %d/%d...", finalCi + 1, totalChunks)));
565→
566→                int start = ci * chunkSamples;
567→                // 加1秒重叠避免截断
568→                int overlap = ci > 0 ? 16000 : 0;
569→                int actualStart = Math.max(0, start - overlap);
570→                int end = Math.min(samples.length, start + chunkSamples);
571→                int len = end - actualStart;
572→
573→                if (len < 1600) continue; // 不足0.1秒跳过
574→
575→                float[] chunk = new float[len];
576→                System.arraycopy(samples, actualStart, chunk, 0, len);
577→
578→                OfflineStream stream = recognizer.createStream();
579→                stream.acceptWaveform(chunk, 16000);
580→                recognizer.decode(stream);
581→                OfflineRecognizerResult result = recognizer.getResult(stream);
582→                String text = result.getText() != null ? result.getText().trim() : "";
583→
584→                if (!text.isEmpty()) {
585→                    // 去除重叠部分导致的重复（最长公共后缀/前缀匹配，窗口30字）
586→                    if (ci > 0 && allText.length() > 0 && overlap > 0) {
587→                        String prev = allText.toString();
588→                        int maxCheck = Math.min(30, Math.min(prev.length(), text.length()));
589→                        int bestMatch = 0;
590→                        for (int t = maxCheck; t > 0; t--) {
591→                            if (prev.endsWith(text.substring(0, t))) {
592→                                bestMatch = t;
593→                                break;
594→                            }
595→                        }
596→                        if (bestMatch > 0) {
597→                            text = text.substring(bestMatch);
598→                        }
599→                    }
600→                    allText.append(text);
601→                }
602→                stream.release();
603→            }
604→        }
605→
606→        recognizer.release();
607→        return allText.toString().trim();
608→    }
