696→                String summary = result.callAttr("get", "summary").toString();
697→                PyObject diffsObj = result.callAttr("get", "diffs");
698→
699→                // LLM智能审核：过滤转写误差（同音字等）
700→                SharedPreferences prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
701→                String llmProvider = prefs.getString("llm_provider_id", "");
702→                String llmKey = llmProvider.isEmpty() ? "" : prefs.getString("llm_key_" + llmProvider, "");
703→                boolean llmEnabled = prefs.getBoolean("llm_enabled", true);  // 用户可选择是否启用
704→                if (llmEnabled && !llmProvider.isEmpty() && !llmKey.isEmpty()) {
705→                    Log.i(TAG, "开始LLM审核: provider=" + llmProvider);
706→                    runOnUiThread(() -> tvStatus.setText("大模型审核差异中..."));
707→                    try {
708→                        diffsObj = engine.callAttr("llm_review_diffs",
709→                            diffsObj, lastDocText, audioText, llmProvider, llmKey);
710→                        // 更新摘要
711→                        int totalDiffs = diffsObj.asList().size();
712→                        int nMis = 0, nMiss = 0, nExt = 0;
713→                        for (PyObject d : diffsObj.asList()) {
714→                            String t = d.callAttr("get", "type", "").toString();
715→                            if ("mismatch".equals(t)) nMis++;
716→                            else if ("missing".equals(t)) nMiss++;
717→                            else nExt++;
718→                        }
719→                        summary = String.format("共%d处差异：%d处误读，%d处漏读，%d处多读\n(已经大模型审核过滤)",
720→                            totalDiffs, nMis, nMiss, nExt);
721→                        Log.i(TAG, "LLM审核完成: " + totalDiffs + "处差异保留");
722→                    } catch (Exception e) {
723→                        Log.w(TAG, "LLM审核失败，使用原始结果: " + e.getMessage());
724→                    }
725→                } else {
726→                    Log.i(TAG, "跳过LLM审核: enabled=" + llmEnabled + " provider=" + llmProvider + " key=" + (llmKey.isEmpty() ? "空" : "有"));
727→                }
728→
729→                // 保存结构化差异JSON（含时间戳）
730→                lastDiffsJson = jsonMod.callAttr("dumps", diffsObj,
731→                    new com.chaquo.python.Kwarg("ensure_ascii", false)).toString();
732→
733→                // 格式化显示
734→                StringBuilder details = new StringBuilder();
735→                int idx = 1;
736→                for (PyObject d : diffsObj.asList()) {
737→                    String dtype = d.callAttr("get", "type", "").toString();
738→                    String docT = d.callAttr("get", "docText", "").toString();
739→                    String audioT = d.callAttr("get", "audioText", "").toString();
740→                    if ("mismatch".equals(dtype)) {
741→                        details.append(idx).append(". [误读] 原文: ")
742→                            .append(docT).append(" → 录音: ").append(audioT);
743→                    } else if ("missing".equals(dtype)) {
744→                        details.append(idx).append(". [漏读] ").append(docT);
745→                    } else {
746→                        details.append(idx).append(". [多读] ").append(audioT);
747→                    }
748→                    // 显示时间戳（精确到秒）
749→                    PyObject tsObj = d.callAttr("get", "time_start");
