751→                        try {
752→                            double ts = tsObj.toDouble();
753→                            int m = (int) ts / 60;
754→                            int s = (int) ts % 60;
755→                            details.append("  ⏰ ").append(m).append("分").append(s).append("秒");
756→                        } catch (Exception ignore) {}
757→                    }
758→                    details.append("\n");
759→                    idx++;
760→                }
761→
762→                String finalDetails = details.toString();
763→                String finalSummary = summary;
764→
765→                // 保存结果
766→                lastAudioText = audioText;
767→                lastReportPath = "";
768→
769→                runOnUiThread(() -> {
770→                    tvStatus.setText("对比完成");
771→                    tvResult.setText(finalSummary + "\n\n" + finalDetails);
772→                    scrollResult.setVisibility(View.VISIBLE);
773→                    progressBar.setVisibility(View.GONE);
774→                    btnCompare.setEnabled(true);
775→                    if (btnGenerateReport != null) btnGenerateReport.setVisibility(View.VISIBLE);
776→                    if (btnShare != null) btnShare.setVisibility(View.VISIBLE);
777→                });
778→            } catch (Exception e) {
779→                Log.e(TAG, "处理失败", e);
780→                String errMsg = e.getMessage();
781→                if (errMsg == null) errMsg = e.getClass().getSimpleName();
782→                String finalErr = errMsg;
783→                runOnUiThread(() -> {
784→                    tvStatus.setText("错误: " + finalErr);
785→                    progressBar.setVisibility(View.GONE);
786→                    btnCompare.setEnabled(true);
787→                });
788→            }
789→        }).start();
790→    }
