# 保持 Sherpa-ONNX 本地库
-keep class com.k2fsa.sherpa.onnx.** { *; }

# 保持 Activity（AndroidManifest 引用）
-keep public class com.voicedoc.app.MainActivity { *; }
-keep public class com.voicedoc.app.SettingsActivity { *; }

# 保持 native 方法
-keepclasseswithmembernames class * {
    native <methods>;
}

# 保持序列化
-keepclassmembers class * implements java.io.Serializable {
    static final long serialVersionUID;
    private static final java.io.ObjectStreamField[] serialPersistentFields;
    !static !transient <fields>;
    private void writeObject(java.io.ObjectOutputStream);
    private void readObject(java.io.ObjectInputStream);
    java.lang.Object writeReplace();
    java.lang.Object readResolve();
}

# 保持 Parcelable
-keep class * implements android.os.Parcelable {
    public static final android.os.Parcelable$Creator *;
}

# 保持 enum
-keepclassmembers enum * {
    public static **[] values();
    public static ** valueOf(java.lang.String);
}

# 保持 R 文件
-keepclassmembers class **.R$* {
    public static <fields>;
}

# 保持 ContentProvider
-keep public class * extends android.content.ContentProvider { *; }
-keep class androidx.core.content.FileProvider { *; }

# 保持 AndroidX
-keep class androidx.appcompat.** { *; }
-keep class com.google.android.material.** { *; }
-keep class androidx.constraintlayout.** { *; }

# ==================== 资源混淆 ====================
# 移除 SourceFile 和 LineNumberTable（反编译无法看到源码信息）
-renamesourcefileattribute ''
-keepattributes Exceptions,InnerClasses,Signature,Deprecated,EnclosingMethod

# 移除 Annotation（减少反编译信息）
-keepattributes *Annotation*

toolUseResult.originalFile:
# VoiceDocCompare ProGuard Rules
# 单夫纯律师制作，保留全部权利

# 保持 Python 相关类
-keep class com.chaquo.python.** { *; }
-keep class com.chaquo.pyhpy.** { *; }
-keep @com.chaquo.python.annotations.* class * { *; }
-keep class com.chaquo.pyho.** { *; }

# 保持 Python 接口
-keep class com.chaquo.python.PyObject { *; }
-keep class com.chaquo.python.PyException { *; }
-keep class com.chaquo.python.Kwarg { *; }

# 保持 Sherpa-ONNX
-keep class com.k2fsa.sherpa.onnx.** { *; }
-dontwarn com.k2fsa.sherpa.onnx.**

# 保持数据类
-keepclass * implements java.io.Serializable { *; }
-keepclass * implements android.os.Parcelable { *; }

# 保持 MainActivity
-keep class com.voicedoc.app.MainActivity { *; }
-keepclass com.voicedoc.app.MainActivity$* { *; }

# 保持 SettingsActivity
-keep class com.voicedoc.app.SettingsActivity { *; }
-keepclass com.voicedoc.app.SettingsActivity$* { *; }

# 保持本地 native 方法
-keepclasseswithmembernames class * {
    native <methods>;
}

input.content:
plugins {
    id 'com.android.application'
    id 'com.chaquo.python'
}

android {
    namespace 'com.voicedoc.app'
    compileSdk 34

    defaultConfig {
        applicationId "com.voicedoc.app"
        minSdk 24
        targetSdk 34
        versionCode 7
        versionName "3.0.0"

        python {
            version "3.11"
            buildPython "C:/Users/Administrator/funasr-venv/Scripts/python.exe"
            pip {
                install "requests"
                install "python-docx"
                install "pypinyin"
                install "jieba"
            }
        }

        ndk {
            abiFilters "arm64-v8a"
        }
    }

    signingConfigs {
        release {
            storeFile file("${rootDir}/release-key.jks")
            storePassword "VoiceDoc2024"
            keyAlias "voicedoc"
            keyPassword "VoiceDoc2024"
        }
    }

    buildTypes {
        release {
            // 最高级代码混淆
            minifyEnabled true
            shrinkResources true
            proguardFiles getDefaultProguardFile('proguard-android-optimize.txt'), 'proguard-rules.pro'
            signingConfig signingConfigs.release

            // 调试信息全部移除
            debuggable false
            jniDebuggable false
            renderscriptDebuggable false

            // 压缩优化
            crunchPngs true
        }

        debug {
            minifyEnabled false
            debuggable true
        }
    }

    // R8 全模式（最激进的优化和混淆）
    compileOptions {
        sourceCompatibility JavaVersion.VERSION_1_8
        targetCompatibility JavaVersion.VERSION_1_8
    }

    sourceSets {
        main {
            python.srcDirs = ["src/main/python"]
        }
    }
}

dependencies {
    implementation 'androidx.appcompat:appcompat:1.6.1'
    implementation 'com.google.android.material:material:1.11.0'
    implementation 'androidx.constraintlayout:constraintlayout:2.1.4'
    implementation files('libs/sherpa-onnx-1.12.25.aar')
    implementation 'org.jetbrains.kotlin:kotlin-stdlib:1.9.22'
}

